import React, { useState } from 'react';
import BottomNav from './components/BottomNav';
import FilterScreen from './components/FilterScreen';
import ReviewScreen from './components/ReviewScreen';
import CheckoutScreen from './components/CheckoutScreen';

const App: React.FC = () => {
  // Simple view state to switch between screens for demonstration
  // Defaulting to 'checkout' as per request
  const [currentScreen, setCurrentScreen] = useState<'filter' | 'review' | 'checkout'>('checkout');

  const navigateToReview = () => setCurrentScreen('review');
  const navigateToFilter = () => setCurrentScreen('filter');
  const navigateToCheckout = () => setCurrentScreen('checkout');

  return (
    <div className="min-h-screen max-w-md mx-auto bg-gray-50 md:shadow-xl md:border-x md:border-gray-200 flex flex-col relative">
      <div className="flex-1">
        {currentScreen === 'filter' ? (
          <FilterScreen onBack={navigateToCheckout} />
        ) : currentScreen === 'review' ? (
          <ReviewScreen onBack={navigateToCheckout} />
        ) : (
          <CheckoutScreen onBack={navigateToFilter} />
        )}
      </div>

      <BottomNav />

      {/* Dev Helper to navigate between screens */}
      <div className="fixed top-24 right-0 z-50 flex flex-col items-end gap-1 p-2 pointer-events-none">
         <div className="pointer-events-auto flex flex-col gap-1 bg-black/10 backdrop-blur-md rounded-l-lg p-1">
            <button onClick={navigateToCheckout} className={`px-2 py-1 text-[10px] rounded ${currentScreen === 'checkout' ? 'bg-white text-black font-bold' : 'text-white hover:bg-white/20'}`}>Checkout</button>
            <button onClick={navigateToFilter} className={`px-2 py-1 text-[10px] rounded ${currentScreen === 'filter' ? 'bg-white text-black font-bold' : 'text-white hover:bg-white/20'}`}>Filter</button>
            <button onClick={navigateToReview} className={`px-2 py-1 text-[10px] rounded ${currentScreen === 'review' ? 'bg-white text-black font-bold' : 'text-white hover:bg-white/20'}`}>Review</button>
         </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { ReviewCategory } from '../types';

interface RatingCardProps {
  rating: number;
  category: ReviewCategory;
  onRatingChange: (rating: number) => void;
  onCategoryChange: (category: ReviewCategory) => void;
}

const RatingCard: React.FC<RatingCardProps> = ({
  rating,
  category,
  onRatingChange,
  onCategoryChange,
}) => {
  const renderStarRow = (starCount: number, widthPercent: string) => {
    // In this design, the user likely selects a rating by tapping the row.
    // The bars seem to be a visual indicator of "level" rather than a distribution in this context,
    // or simply a stylistic choice for the input options.
    const isSelected = rating === starCount;

    return (
      <button
        key={starCount}
        onClick={() => onRatingChange(starCount)}
        className="w-full flex items-center gap-3 py-1.5 group"
      >
        <div className="w-16 text-right">
          <span className="text-white text-xs font-semibold">
            {starCount} Star{starCount > 1 ? 's' : ''}
          </span>
        </div>

        <div className="flex-1 h-3.5 bg-white rounded-full overflow-hidden p-[2px]">
          <div
            className={`h-full rounded-full transition-all duration-300 ${
              isSelected ? 'opacity-100' : 'opacity-60 group-hover:opacity-80'
            }`}
            style={{ 
              width: widthPercent,
              backgroundColor: '#FF6B6B' // Pinkish red from image
            }}
          />
        </div>
      </button>
    );
  };

  return (
    <div className="bg-[#2ECC71] rounded-xl p-5 shadow-sm mb-4">
      <div className="flex flex-col items-center mb-6">
        <h2 className="text-white text-lg font-medium mb-4">Rate your experience for</h2>

        {/* Custom Toggle */}
        <div className="flex items-center gap-6">
           <label className="flex items-center gap-2 cursor-pointer">
              <div className={`w-5 h-5 rounded-full bg-white flex items-center justify-center transition-all`}>
                 {category === 'Shopping' && <div className="w-5 h-5 rounded-full bg-white border-4 border-[#2ECC71]" />}
                 {category !== 'Shopping' && <div className="w-5 h-5 rounded-full bg-white opacity-40" />}
              </div>
              <span className="text-white font-medium text-sm">Shopping</span>
              <input 
                 type="radio" 
                 className="hidden" 
                 checked={category === 'Shopping'} 
                 onChange={() => onCategoryChange('Shopping')}
              />
           </label>

           <label className="flex items-center gap-2 cursor-pointer">
              <div className={`w-5 h-5 rounded-full bg-white flex items-center justify-center transition-all`}>
                 {category === 'Delivery' && <div className="w-5 h-5 rounded-full bg-white border-4 border-[#2ECC71]" />}
                 {category !== 'Delivery' && <div className="w-5 h-5 rounded-full bg-white opacity-40" />}
              </div>
              <span className="text-white font-medium text-sm">Delivery</span>
              <input 
                 type="radio" 
                 className="hidden" 
                 checked={category === 'Delivery'} 
                 onChange={() => onCategoryChange('Delivery')}
              />
           </label>
        </div>
      </div>

      <div className="space-y-2.5 px-2">
        {renderStarRow(5, '100%')}
        {renderStarRow(4, '80%')}
        {renderStarRow(3, '60%')}
        {renderStarRow(2, '40%')}
        {renderStarRow(1, '20%')}
      </div>
    </div>
  );
};

export default RatingCard;

import React, { useState } from 'react';
import { Tag } from '../types';
import { Search, Plus, Frown, Smile } from 'lucide-react';

interface TagSectionProps {
  title: string;
  emoji: 'happy' | 'sad';
  tags: Tag[];
  selectedTagIds: string[];
  onToggleTag: (id: string) => void;
  searchPlaceholder?: string;
}

const TagSection: React.FC<TagSectionProps> = ({
  title,
  emoji,
  tags,
  selectedTagIds,
  onToggleTag,
  searchPlaceholder = "Search tag or select from below"
}) => {
  const [searchQuery, setSearchQuery] = useState('');

  const filteredTags = tags.filter(tag => 
    tag.label.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="bg-white p-5 rounded-xl shadow-sm mb-4">
      <div className="flex items-center gap-2 mb-4">
        <h3 className="text-gray-900 font-bold text-lg">{title}</h3>
        {emoji === 'sad' ? (
          <Frown className="w-6 h-6 text-red-400 stroke-[1.5]" />
        ) : (
          <Smile className="w-6 h-6 text-red-400 stroke-[1.5]" />
        )}
      </div>

      <div className="relative mb-4">
        <input
          type="text"
          placeholder={searchPlaceholder}
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full bg-white border border-gray-100 text-sm py-3 px-4 rounded-lg placeholder-gray-300 focus:outline-none focus:ring-1 focus:ring-red-200"
        />
      </div>

      <div className="flex flex-wrap gap-2">
        {filteredTags.map((tag) => {
          const isSelected = selectedTagIds.includes(tag.id);
          return (
            <button
              key={tag.id}
              onClick={() => onToggleTag(tag.id)}
              className={`px-4 py-2 rounded-md text-xs font-medium transition-colors duration-200 ${
                isSelected
                  ? 'bg-[#EF4444] text-white shadow-sm'
                  : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              {tag.label}
            </button>
          );
        })}
        {filteredTags.length === 0 && searchQuery && (
          <button 
            onClick={() => console.log('New tag added:', searchQuery)}
            className="flex items-center gap-1 px-3 py-2 rounded-md text-xs bg-gray-50 text-gray-400 border border-dashed border-gray-300 hover:bg-gray-100 transition-colors"
          >
            <Plus className="w-3 h-3" /> Add "{searchQuery}"
          </button>
        )}
      </div>
    </div>
  );
};

export default TagSection;

import React, { useRef, useState } from 'react';
import { Camera, X, Image as ImageIcon } from 'lucide-react';
import { PhotoAttachment } from '../types';

interface PhotoUploadSectionProps {
  photos: PhotoAttachment[];
  onAddPhoto: (files: File[]) => void;
  onRemovePhoto: (id: string) => void;
  onRetryPhoto: (id: string) => void;
  onReorderPhotos: (photos: PhotoAttachment[]) => void;
}

const PhotoUploadSection: React.FC<PhotoUploadSectionProps> = ({ photos, onAddPhoto, onRemovePhoto }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onAddPhoto(Array.from(e.target.files));
      e.target.value = '';
    }
  };

  return (
    <div className="bg-white p-5 rounded-xl shadow-sm mb-4">
      <h3 className="text-gray-900 font-bold text-lg mb-4">Add Photos</h3>

      <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
        {/* Main Upload Button - Styled as a large square placeholder */}
        <button
          onClick={() => fileInputRef.current?.click()}
          className="flex-shrink-0 w-24 h-24 bg-gray-200 rounded-lg flex items-center justify-center hover:bg-gray-300 transition-colors"
        >
          <div className="bg-white p-2 rounded-full shadow-sm">
             <Camera className="w-5 h-5 text-gray-400" />
          </div>
        </button>

        {/* Photo Previews */}
        {photos.map((photo) => (
          <div 
            key={photo.id}
            className="relative flex-shrink-0 w-24 h-24 rounded-lg overflow-hidden border border-gray-100"
          >
            <img 
              src={photo.url} 
              alt="Upload" 
              className="w-full h-full object-cover" 
            />

            <button
              onClick={() => onRemovePhoto(photo.id)}
              className="absolute top-1 right-1 bg-black/50 hover:bg-black/70 text-white rounded-full p-1"
            >
              <X className="w-3 h-3" />
            </button>

            {photo.status === 'uploading' && (
              <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                 <div className="w-6 h-6 rounded-full border-2 border-white/30 border-t-white animate-spin"></div>
              </div>
            )}
          </div>
        ))}

        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept="image/*"
          multiple
          onChange={handleFileChange}
        />
      </div>
    </div>
  );
};

export default PhotoUploadSection;

import React, { useState } from 'react';
import { ChevronLeft, Edit2 } from 'lucide-react';
import { Tag, ReviewState, PhotoAttachment } from '../types';
import TagSection from './TagSection';
import RatingCard from './RatingCard';
import PhotoUploadSection from './PhotoUploadSection';
import { generateReviewText } from '../services/geminiService';

// Mock Data
const NEGATIVE_TAGS: Tag[] = [
  { id: 'n1', label: 'Neat packging' },
  { id: 'n2', label: 'Average portion size' },
  { id: 'n3', label: 'Poor packaging' },
  { id: 'n4', label: 'Packaging was not tamper proof' },
];

const POSITIVE_TAGS: Tag[] = [
  { id: 'p1', label: 'Contactless delivery' },
  { id: 'p2', label: 'Economical price' },
  { id: 'p3', label: 'Good Quality' },
  { id: 'p4', label: 'Tamper proof packaging' },
  { id: 'p5', label: 'Wonderful presentation' },
  { id: 'p6', label: 'Fair prices' },
];

interface ReviewScreenProps {
  onBack?: () => void;
}

const ReviewScreen: React.FC<ReviewScreenProps> = ({ onBack }) => {
  const [reviewState, setReviewState] = useState<ReviewState>({
    rating: 5,
    category: 'Shopping',
    selectedNegativeTags: ['n2'], // Pre-selecting for visual match with mock
    selectedPositiveTags: ['p2'], // Pre-selecting for visual match with mock
    reviewText: '',
    photos: []
  });

  const [isGenerating, setIsGenerating] = useState(false);

  const handleToggleNegativeTag = (id: string) => {
    setReviewState(prev => {
      const isSelected = prev.selectedNegativeTags.includes(id);
      return {
        ...prev,
        selectedNegativeTags: isSelected
          ? prev.selectedNegativeTags.filter(t => t !== id)
          : [...prev.selectedNegativeTags, id]
      };
    });
  };

  const handleTogglePositiveTag = (id: string) => {
    setReviewState(prev => {
      const isSelected = prev.selectedPositiveTags.includes(id);
      return {
        ...prev,
        selectedPositiveTags: isSelected
          ? prev.selectedPositiveTags.filter(t => t !== id)
          : [...prev.selectedPositiveTags, id]
      };
    });
  };

  const handleAddPhotos = (files: File[]) => {
    if (files.length === 0) return;
    const newAttachments = files.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      url: URL.createObjectURL(file),
      status: 'uploading' as const,
      progress: 0
    }));

    setReviewState(prev => ({
      ...prev,
      photos: [...prev.photos, ...newAttachments]
    }));

    // Simulate immediate upload completion for demo
    setTimeout(() => {
        setReviewState(prev => ({
            ...prev,
            photos: prev.photos.map(p => p.status === 'uploading' ? { ...p, status: 'complete' } : p)
        }));
    }, 1500);
  };

  const handleRemovePhoto = (id: string) => {
    setReviewState(prev => ({
      ...prev,
      photos: prev.photos.filter(p => p.id !== id)
    }));
  };

  const handleReorderPhotos = (newPhotos: PhotoAttachment[]) => {
    setReviewState(prev => ({ ...prev, photos: newPhotos }));
  };

  const handleGenerateAIReview = async () => {
    setIsGenerating(true);
    try {
      const posLabels = POSITIVE_TAGS.filter(t => reviewState.selectedPositiveTags.includes(t.id)).map(t => t.label);
      const negLabels = NEGATIVE_TAGS.filter(t => reviewState.selectedNegativeTags.includes(t.id)).map(t => t.label);

      const generatedText = await generateReviewText(
        reviewState.rating,
        reviewState.category,
        posLabels,
        negLabels
      );

      setReviewState(prev => ({ ...prev, reviewText: generatedText }));
    } catch (error) {
      console.error(error);
      // Fallback text if API fails
      setReviewState(prev => ({ ...prev, reviewText: "This was a great experience! The delivery was fast and the quality was excellent." }));
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="bg-gray-50 min-h-screen pb-20 font-sans">
      {/* Header */}
      <header className="flex justify-between items-center px-6 py-5 bg-white sticky top-0 z-40 shadow-sm">
        <button onClick={onBack} className="w-8 h-8 flex items-center justify-center bg-gray-100 rounded-lg hover:bg-gray-200">
          <ChevronLeft className="w-5 h-5 text-gray-600" strokeWidth={2.5} />
        </button>
        <h1 className="text-lg font-bold text-gray-900">Add Review</h1>
        <button className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-gray-50">
          <Edit2 className="w-5 h-5 text-red-500" strokeWidth={2} />
        </button>
      </header>

      {/* Main Content */}
      <main className="px-5 py-6 space-y-6">
        {/* Rating Card */}
        <RatingCard
          rating={reviewState.rating}
          category={reviewState.category}
          onRatingChange={(r) => setReviewState(prev => ({ ...prev, rating: r }))}
          onCategoryChange={(c) => setReviewState(prev => ({ ...prev, category: c }))}
        />

        {/* Negative Tags */}
        <TagSection
          title="What was not upto the Mark?"
          emoji="sad"
          tags={NEGATIVE_TAGS}
          selectedTagIds={reviewState.selectedNegativeTags}
          onToggleTag={handleToggleNegativeTag}
        />

        {/* Positive Tags */}
        <TagSection
          title="What did you like?"
          emoji="happy"
          tags={POSITIVE_TAGS}
          selectedTagIds={reviewState.selectedPositiveTags}
          onToggleTag={handleTogglePositiveTag}
        />

        {/* Add Photos */}
        <PhotoUploadSection 
          photos={reviewState.photos}
          onAddPhoto={handleAddPhotos}
          onRemovePhoto={handleRemovePhoto}
          onRetryPhoto={() => {}}
          onReorderPhotos={handleReorderPhotos}
        />

        {/* Review Text Area */}
        <div className="bg-white p-5 rounded-xl shadow-sm">
          <h3 className="text-gray-900 font-bold text-lg mb-4">Write a review</h3>
          <textarea
            className="w-full h-32 p-4 bg-gray-50 rounded-xl text-sm text-gray-700 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-[#2ECC71] resize-none border-none"
            placeholder="Your review will help people make better choices."
            value={reviewState.reviewText}
            onChange={(e) => setReviewState(prev => ({ ...prev, reviewText: e.target.value }))}
          />
           <div className="flex justify-end mt-2">
            <button 
                onClick={handleGenerateAIReview}
                disabled={isGenerating}
                className="text-xs text-[#2ECC71] font-medium hover:underline flex items-center gap-1"
            >
                {isGenerating ? 'Generating...' : 'Auto-fill with AI'}
            </button>
          </div>
        </div>

        {/* Submit Button */}
        <button 
          className="w-full bg-[#2ECC71] hover:bg-green-500 text-white font-semibold py-4 rounded-xl shadow-lg shadow-green-100 transition-all active:scale-[0.98] text-base"
          onClick={() => alert(`Submitted ${reviewState.category} Review!`)}
        >
          Submit {reviewState.category} Review
        </button>
      </main>
    </div>
  );
};

export default ReviewScreen;

