import React, { useRef, useState } from 'react';
import { Camera, X, Image as ImageIcon, RotateCw, AlertCircle } from 'lucide-react';
import { PhotoAttachment } from '../types';

interface PhotoUploadSectionProps {
  photos: PhotoAttachment[];
  onAddPhoto: (files: File[]) => void;
  onRemovePhoto: (id: string) => void;
  onRetryPhoto: (id: string) => void;
  onReorderPhotos: (photos: PhotoAttachment[]) => void;
}

const PhotoUploadSection: React.FC<PhotoUploadSectionProps> = ({
  photos,
  onAddPhoto,
  onRemovePhoto,
  onRetryPhoto,
  onReorderPhotos
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onAddPhoto(Array.from(e.target.files));
      e.target.value = '';
    }
  };

  const handleDragStart = (e: React.DragEvent<HTMLDivElement>, index: number) => {
    setDraggedIndex(index);
    // Required for some browsers to allow drag
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>, index: number) => {
    e.preventDefault(); // Necessary to allow dropping
    if (draggedIndex === null || draggedIndex === index) return;

    const newPhotos = [...photos];
    const draggedItem = newPhotos[draggedIndex];

    // Remove dragged item
    newPhotos.splice(draggedIndex, 1);
    // Insert at new position
    newPhotos.splice(index, 0, draggedItem);

    onReorderPhotos(newPhotos);
    setDraggedIndex(index);
  };

  const handleDragEnd = () => {
    setDraggedIndex(null);
  };

  return (
    <div className="bg-white p-5 rounded-xl shadow-sm mb-4">
      <h3 className="text-gray-900 font-bold text-lg mb-4">Add Photos</h3>

      <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
        {/* Main Upload Button - Styled as a large square placeholder */}
        <button
          onClick={() => fileInputRef.current?.click()}
          className="flex-shrink-0 w-24 h-24 bg-gray-200 rounded-lg flex items-center justify-center hover:bg-gray-300 transition-colors"
        >
          <div className="bg-white p-2 rounded-full shadow-sm">
             <Camera className="w-5 h-5 text-gray-400" />
          </div>
        </button>

        {/* Photo Previews */}
        {photos.map((photo, index) => (
          <div 
            key={photo.id}
            draggable={photo.status !== 'uploading'}
            onDragStart={(e) => handleDragStart(e, index)}
            onDragOver={(e) => handleDragOver(e, index)}
            onDragEnd={handleDragEnd}
            className={`relative flex-shrink-0 w-24 h-24 rounded-lg overflow-hidden border transition-all duration-200 
              ${photo.status === 'error' ? 'border-red-500' : 'border-gray-100'}
              ${draggedIndex === index ? 'opacity-50 scale-95' : 'opacity-100'}
              cursor-grab active:cursor-grabbing
            `}
          >
            <img 
              src={photo.url} 
              alt="Upload" 
              className="w-full h-full object-cover pointer-events-none" 
            />

            <button
              onClick={() => onRemovePhoto(photo.id)}
              className="absolute top-1 right-1 bg-black/50 hover:bg-black/70 text-white rounded-full p-1 z-10"
            >
              <X className="w-3 h-3" />
            </button>

            {/* Uploading State */}
            {photo.status === 'uploading' && (
              <div className="absolute inset-0 flex items-center justify-center bg-black/40 z-0">
                 <div className="w-6 h-6 rounded-full border-2 border-white/30 border-t-white animate-spin"></div>
              </div>
            )}

            {/* Error State */}
            {photo.status === 'error' && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 z-0 text-red-500">
                 <AlertCircle className="w-6 h-6 mb-1" />
                 <button 
                   onClick={() => onRetryPhoto(photo.id)}
                   className="flex items-center gap-1 text-[10px] font-bold uppercase tracking-wide bg-red-100 text-red-600 px-2 py-1 rounded-full hover:bg-red-200 transition-colors"
                 >
                   Retry <RotateCw className="w-3 h-3" />
                 </button>
              </div>
            )}
          </div>
        ))}

        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept="image/*"
          multiple
          onChange={handleFileChange}
        />
      </div>
    </div>
  );
};

