          onClick={() => fileInputRef.current?.click()}
          className="flex-shrink-0 w-24 h-24 bg-gray-50 border-2 border-dashed border-gray-300 rounded-xl flex flex-col items-center justify-center hover:bg-gray-100 hover:border-brand-orange hover:text-brand-orange transition-all group"
        >
          <div className="bg-white p-2 rounded-full shadow-sm mb-1 group-hover:scale-110 transition-transform">
             <Camera className="w-5 h-5 text-gray-400 group-hover:text-brand-orange" />
          </div>
          <span className="text-[10px] font-medium text-gray-400 group-hover:text-brand-orange">Add Photo</span>
        </button>

        {/* Photo Previews */}
        {photos.map((photo, index) => {
           const isDragged = draggedIndex === index;
           return (
            <div 
              key={photo.id}
              draggable={photo.status !== 'uploading'}
              onDragStart={(e) => handleDragStart(e, index)}
              onDragOver={(e) => handleDragOver(e, index)}
              onDragEnd={handleDragEnd}
              className={`relative flex-shrink-0 w-24 h-24 rounded-xl overflow-hidden transition-all duration-300 ease-out
                ${isDragged 
                  ? 'border-2 border-dashed border-brand-orange bg-orange-50 scale-95 opacity-100' 
                  : photo.status === 'error' ? 'border border-red-500' : 'border border-gray-200 hover:border-brand-orange hover:shadow-md'
                }
                ${!isDragged && photo.status !== 'uploading' ? 'cursor-grab active:cursor-grabbing' : ''}
